# How To Find The EXACT Company Description To Include In Your Email

# How To Find The EXACT Company Description To Include In Your Email

We have automated the process of allowing your to find the EXACT company description of the leads you’re targeting so you can send more personalised and relevant emails

## Auto-Populating Companies Service Descriptions

[https://www.loom.com/share/c691a5b81c764608bfcdef9702bb8ef2?sid=781d289a-64f4-497f-bafa-0cae157e735c](https://www.loom.com/share/c691a5b81c764608bfcdef9702bb8ef2?sid=781d289a-64f4-497f-bafa-0cae157e735c)

### Script To Paste Into Apps Script As Per Above

- **Script**

    ```jsx
    function onOpen() {
      const ui = SpreadsheetApp.getUi();
      ui.createMenu('Company Description') // Updated menu title
        .addItem('Run', 'runImporter')
        .addToUi();
    }

    function runImporter() {
      const ui = SpreadsheetApp.getUi();
      const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();

      // Prompt for column letters for inputs
      const keywordsColumn = ui.prompt('Enter the letter of the column that contains the company keywords:').getResponseText().toUpperCase();
      const websitesColumn = ui.prompt('Enter the letter of the column that contains the website URLs:').getResponseText().toUpperCase();

      // Prompt for column letters for outputs
      const seoDataColumn = ui.prompt('Enter the letter of the column for SEO/Meta Data output:').getResponseText().toUpperCase();
      const pageTitleColumn = ui.prompt('Enter the letter of the column for Page Title output:').getResponseText().toUpperCase();
      const descriptionOutputColumn = ui.prompt('Enter the letter of the column for Company Description output:').getResponseText().toUpperCase();

      // Format output columns
      formatOutputColumn(sheet, seoDataColumn, 'SEO Data');
      formatOutputColumn(sheet, pageTitleColumn, 'Page Title');
      formatOutputColumn(sheet, descriptionOutputColumn, 'Company Description');

      const lastRow = sheet.getLastRow();
      for (let i = 2; i <= lastRow; i++) {
        fetchAndProcessURL(sheet, websitesColumn, i, seoDataColumn, pageTitleColumn);
        generateCompanyDescription(sheet, keywordsColumn, i, seoDataColumn, pageTitleColumn, descriptionOutputColumn);
      }

      // Highlight not found descriptions in red
      highlightCoreServicesNotFound(sheet, descriptionOutputColumn, lastRow);
    }

    function formatOutputColumn(sheet, columnLetter, headerText) {
      const cell = sheet.getRange(`${columnLetter}1`);
      cell.setValue(headerText);
      cell.setBackground('orange');
      cell.setFontWeight('bold');
    }

    function fetchAndProcessURL(sheet, websitesColumn, row, seoDataColumn, pageTitleColumn) {
      const url = sheet.getRange(`${websitesColumn}${row}`).getValue();
      if (url) {
        const response = UrlFetchApp.fetch(url, {muteHttpExceptions: true});
        if (response.getResponseCode() == 200) {
          const content = response.getContentText();
          const metaDescription = content.match(/<meta name="description" content="([^"]*)"/i)?.[1] || "Not Found";
          const pageTitle = content.match(/<title>(.*?)<\/title>/is)?.[1] || "Not Found";
          sheet.getRange(`${seoDataColumn}${row}`).setValue(metaDescription);
          sheet.getRange(`${pageTitleColumn}${row}`).setValue(pageTitle);
        }
      }
    }

    function generateCompanyDescription(sheet, keywordsColumn, row, seoDataColumn, pageTitleColumn, descriptionOutputColumn) {
      const keywords = sheet.getRange(`${keywordsColumn}${row}`).getValue();
      const seoData = sheet.getRange(`${seoDataColumn}${row}`).getValue();
      const pageTitle = sheet.getRange(`${pageTitleColumn}${row}`).getValue();

      // Construct the OpenAI prompt
      const prompt = `Using the keywords "${keywords}", SEO meta description "${seoData}", and title "${pageTitle}", identify the company's core services or offerings and provide a concise label for it. For example, if the keywords are "ppc & paid social", the SEO meta description is "Boost your brand's growth with DemandMore, a leading performance marketing agency based in London specialising in paid search, paid social, and programmatic advertising.", and the title is "DemandMore Performance Agency London", the output should simply be "PPC & Paid Social Agency". The output is going to be used in a cold email that will help us personalise our communication with the prospect. The output will be included in the email as follows "As a [output] we can help solve your problems" and so the output must read naturally as their companies service. Follow this format and provide the concise label only.`;

      const description = callOpenAI(prompt);
      sheet.getRange(`${descriptionOutputColumn}${row}`).setValue(description);
    }

    function callOpenAI(prompt) {
      const apiKey = 'YOUR API KEY';
      const url = 'https://api.openai.com/v1/chat/completions';
      const data = {
        model: "gpt-3.5-turbo",
        messages: [{
          "role": "system",
          "content": "You are a helpful assistant."
        },
        {
          "role": "user",
          "content": prompt
        }]
      };
      const options = {
        method: "post",
        contentType: "application/json",
        headers: {
          Authorization: "Bearer " + apiKey
        },
        payload: JSON.stringify(data),
        muteHttpExceptions: true
      };

      const response = UrlFetchApp.fetch(url, options);
      const jsonResponse = JSON.parse(response.getContentText());

      if (response.getResponseCode() === 200 && jsonResponse.choices && jsonResponse.choices.length > 0) {
        return jsonResponse.choices[0].message.content.trim();
      } else {
        Logger.log('API request failed or returned an unexpected format: ' + response.getContentText());
        return 'Description generation failed.';
      }
    }

    function highlightCoreServicesNotFound(sheet, descriptionOutputColumn, lastRow) {
      for (let i = 2; i <= lastRow; i++) {
        const cellValue = sheet.getRange(`${descriptionOutputColumn}${i}`).getValue();
        if (cellValue.includes("Core Services") && cellValue.includes("Not found")) {
          sheet.getRange(`${descriptionOutputColumn}${i}`).setBackground('red');
        }
      }
    }

    ```


