### How to integrate the tool

> Go to Google Sheets

> Click ‘Extensions’

> Click ‘Google Apps Script’

> Delete anything in the script

> Paste the script below 

> Replace ‘Your API Key’ with your OpenAI API key

> Click ‘Save’

> Go back to your Google Sheet and click ‘Refresh’

> It’s ready to go

### Script

```jsx
function onOpen() {
  const ui = SpreadsheetApp.getUi();
  const menu = ui.createMenu('CCG Case Study Tool');

  // Adding submenu items
  menu.addItem('Scrape Company LinkedIn Description', 'getMetaDescription');
  menu.addItem('Check for Case Study', 'checkForCaseStudy');
  menu.addItem('Pull Case Study Names', 'pullCaseStudyNames');
  menu.addToUi();
}

function getMetaDescription() {
  const ui = SpreadsheetApp.getUi();
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();

  const inputColumnPrompt = ui.prompt('Enter the letter of the column that contains the LinkedIn URLs:');
  const inputColumn = inputColumnPrompt.getResponseText().toUpperCase();
  const outputColumnPrompt = ui.prompt('Enter the letter of the column for Meta Description output:');
  const outputColumn = outputColumnPrompt.getResponseText().toUpperCase();

  if (inputColumnPrompt.getSelectedButton() === ui.Button.OK && outputColumnPrompt.getSelectedButton() === ui.Button.OK) {
    // Set the header for the output column
    sheet.getRange(outputColumn + '1').setValue('Company LinkedIn Description').setFontWeight('bold');

    const lastRow = sheet.getLastRow();
    for (let i = 2; i <= lastRow; i++) {
      const linkedinUrl = sheet.getRange(`${inputColumn}${i}`).getValue();
      if (linkedinUrl) {
        const metaDescription = getMetaDescriptionFromURL(linkedinUrl);
        sheet.getRange(`${outputColumn}${i}`).setValue(metaDescription);
      } else {
        sheet.getRange(`${outputColumn}${i}`).setValue('LinkedIn URL not provided');
      }
    }
    ui.alert('Meta descriptions fetched successfully.');
  } else {
    ui.alert('Operation cancelled by the user.');
  }
}

function getMetaDescriptionFromURL(url) {
  try {
    const response = UrlFetchApp.fetch(url, {muteHttpExceptions: true});
    if (response.getResponseCode() == 200) {
      const content = response.getContentText();
      const metaDescriptionMatch = content.match(/<meta\s+name="description"\s+content="([^"]*)"/i);
      if (metaDescriptionMatch && metaDescriptionMatch[1]) {
        return metaDescriptionMatch[1];
      } else {
        return 'Meta description not found';
      }
    } else {
      return 'Error fetching URL';
    }
  } catch (error) {
    return 'Error: ' + error.toString();
  }
}

function checkForCaseStudy() {
  const ui = SpreadsheetApp.getUi();
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const descriptionColumnPrompt = ui.prompt('Enter the letter of the column that contains the Company LinkedIn Descriptions:');
  const descriptionColumn = descriptionColumnPrompt.getResponseText().toUpperCase();

  const outputColumnPrompt = ui.prompt('Enter the letter of the column to output the results:');
  const outputColumn = outputColumnPrompt.getResponseText().toUpperCase();

  if (descriptionColumnPrompt.getSelectedButton() === ui.Button.OK && outputColumnPrompt.getSelectedButton() === ui.Button.OK) {
    // Set the header for the output column and make it bold
    sheet.getRange(outputColumn + '1').setValue('Case Study?').setFontWeight('bold');

    const lastRow = sheet.getLastRow();
    for (let i = 2; i <= lastRow; i++) {
      const linkedinDescription = sheet.getRange(`${descriptionColumn}${i}`).getValue();
      const response = callChatGPTToCheckCaseStudy(linkedinDescription);
      sheet.getRange(`${outputColumn}${i}`).setValue(response);
    }
    ui.alert('Check for case studies completed successfully.');
  } else {
    ui.alert('Operation cancelled by the user.');
  }
}

function callChatGPTToCheckCaseStudy(description) {
  const apiKey = 'YOUR API KEY'; // Hard-coded API key as per instruction
  const url = 'https://api.openai.com/v1/chat/completions';
  const prompt = `Check this data point "${description}" which is a company's LinkedIn description data. We want to check to understand if within this data there is reference to a company that this company has worked with or helped. For example, a company description might say 'With hundreds of exclusive publishers, including EA, Rovio, Scopely.' After reviewing this, if it indicates that the company has worked with another company, output 'Y', otherwise output 'N'.`;

  const data = {
    model: "gpt-3.5-turbo",
    messages: [{
      "role": "system",
      "content": "You are a helpful assistant."
    }, {
      "role": "user",
      "content": prompt
    }]
  };

  const options = {
    method: "post",
    contentType: "application/json",
    headers: {
      Authorization: "Bearer " + apiKey
    },
    payload: JSON.stringify(data),
    muteHttpExceptions: true
  };

  try {
    const response = UrlFetchApp.fetch(url, options);
    if (response.getResponseCode() === 200) {
      const jsonResponse = JSON.parse(response.getContentText());
      if (jsonResponse.choices && jsonResponse.choices.length > 0) {
        const text = jsonResponse.choices[0].message.content.trim();
        // Here, ensuring that 'Y' is only returned if the response explicitly confirms a collaboration.
        return text === 'Y' ? 'Y' : 'N';
      } else {
        return 'No clear answer';
      }
    } else {
      Logger.log('API request failed or returned an unexpected format: ' + response.getContentText());
      return 'Error in API request';
    }
  } catch (error) {
    Logger.log('Error calling API: ' + error.toString());
    return 'Error in API call';
  }
}

function pullCaseStudyNames() {
  const ui = SpreadsheetApp.getUi();
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const descriptionColumnPrompt = ui.prompt('Enter the letter of the column that contains the Company LinkedIn Descriptions:');
  const descriptionColumn = descriptionColumnPrompt.getResponseText().toUpperCase();

  const outputColumnPrompt = ui.prompt('Enter the letter of the column to output the results:');
  const outputColumn = outputColumnPrompt.getResponseText().toUpperCase();

  if (descriptionColumnPrompt.getSelectedButton() === ui.Button.OK && outputColumnPrompt.getSelectedButton() === ui.Button.OK) {
    // Set the header for the output column and make it bold
    sheet.getRange(outputColumn + '1').setValue('Case Study Company').setFontWeight('bold');

    const lastRow = sheet.getLastRow();
    for (let i = 2; i <= lastRow; i++) {
      const linkedinDescription = sheet.getRange(`${descriptionColumn}${i}`).getValue();
      const companyName = callChatGPTToPullCaseStudyName(linkedinDescription);
      sheet.getRange(`${outputColumn}${i}`).setValue(companyName);
    }
    ui.alert('Case study names pulled successfully.');
  } else {
    ui.alert('Operation cancelled by the user.');
  }
}

function callChatGPTToPullCaseStudyName(description) {
  const apiKey = 'YOUR API KEY'; // Hard-coded API key
  const url = 'https://api.openai.com/v1/chat/completions';
  const prompt = `Here's the company's LinkedIn description: "${description}". Within this data point there is reference to a company that this company has worked with. Please provide the name of the company that this company has worked with. Output the name of the company only, without additional text or quotations. If there is more than one, please only provide one as the output.`;

  const data = {
    model: "gpt-3.5-turbo",
    messages: [{
      "role": "system",
      "content": "You are a helpful assistant."
    }, {
      "role": "user",
      "content": prompt
    }]
  };

  const options = {
    method: "post",
    contentType: "application/json",
    headers: {
      Authorization: "Bearer " + apiKey
    },
    payload: JSON.stringify(data),
    muteHttpExceptions: true
  };

  try {
    const response = UrlFetchApp.fetch(url, options);
    if (response.getResponseCode() === 200) {
      const jsonResponse = JSON.parse(response.getContentText());
      if (jsonResponse.choices && jsonResponse.choices.length > 0) {
        return jsonResponse.choices[0].message.content.trim();
      } else {
        return 'No company name found';
      }
    } else {
      Logger.log('API request failed or returned an unexpected format: ' + response.getContentText());
      return 'Error in API request';
    }
  } catch (error) {
    Logger.log('Error calling API: ' + error.toString());
    return 'Error in API call';
  }
}
```

